import{H as e,V as t,et as n,j as r}from"./chunks/framework.C_EfTa_6.js";var i=JSON.parse(`{"title":"主板","description":"","frontmatter":{"title":"主板","order":30},"headers":[],"relativePath":"kernel/equip/motherboard/index.md","filePath":"kernel/equip/motherboard/index.md"}`),a={name:`kernel/equip/motherboard/index.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="主板" tabindex="-1">主板 <a class="header-anchor" href="#主板" aria-label="Permalink to “主板”">​</a></h1><p>主板（Motherboard）是计算机的核心载体，连接 CPU、内存、显卡、存储和各类外设。主板的设计取向决定了整机的能力上限——消费级主板追求单核性能和性价比，工作站主板追求 PCIe 扩展和内存带宽，服务器主板追求可靠性（RAS）和多路扩展。</p><h2 id="三级平台" tabindex="-1">三级平台 <a class="header-anchor" href="#三级平台" aria-label="Permalink to “三级平台”">​</a></h2><p>按应用场景，主板平台分为三个层级，对应不同的 CPU 产品线：</p><table tabindex="0"><thead><tr><th>层级</th><th>定位</th><th>CPU 产品线</th><th>典型平台</th><th>内存通道</th><th>PCIe 通道</th><th>多路</th><th>ECC</th><th>BMC</th></tr></thead><tbody><tr><td>消费级</td><td>个人 PC、游戏</td><td>Ryzen / Core</td><td>AM5 / LGA1851</td><td>2 通道</td><td>24~28 条</td><td>否</td><td>否</td><td>否</td></tr><tr><td>工作站</td><td>影视渲染、AI、EDA</td><td>Threadripper</td><td>sTR5 (TRX50/WRX90)</td><td>4~8 通道</td><td>48~128 条</td><td>否</td><td>部分</td><td>部分</td></tr><tr><td>服务器</td><td>数据中心、云计算</td><td>EPYC / Xeon</td><td>SP5 / SP3</td><td>8~12 通道</td><td>96~160 条</td><td>是</td><td>是</td><td>是</td></tr></tbody></table><p>三级平台的边界不是绝对的。消费级主板的顶级型号（如 X870E）在内存和 PCIe 扩展上已接近入门工作站；而工作站的 WRX90 在 BMC 带外管理和 ECC 内存支持上已具备服务器级特性。真正的分水岭在于架构取向——消费级以芯片组（PCH）为枢纽管理外设，工作站和服务器以 SoC 形式将 PCIe 根复合体集成进 CPU。</p><h2 id="主板与内存的约束" tabindex="-1">主板与内存的约束 <a class="header-anchor" href="#主板与内存的约束" aria-label="Permalink to “主板与内存的约束”">​</a></h2><p>主板和内存之间存在严格的适配关系，不同层级平台的约束差异巨大。</p><table tabindex="0"><thead><tr><th>约束维度</th><th>消费级</th><th>工作站</th><th>服务器</th></tr></thead><tbody><tr><td>内存类型</td><td>UDIMM</td><td>UDIMM/RDIMM</td><td>RDIMM/LRDIMM</td></tr><tr><td>通道数</td><td>2</td><td>4-8</td><td>8-12</td></tr><tr><td>ECC</td><td>部分支持</td><td>Pro 型号支持</td><td>强制</td></tr><tr><td>最大容量</td><td>~192 GB</td><td>1-2 TB</td><td>6+ TB</td></tr><tr><td>XMP/EXPO</td><td>常用</td><td>部分支持</td><td>禁止</td></tr><tr><td>填充规则</td><td>对称即可</td><td>对称 + RDIMM</td><td>严格对称 + NUMA 感知</td></tr></tbody></table><p>消费级主要关注 1 DPC vs 2 DPC 对高频稳定性的影响，以及 XMP/EXPO 不等于即插即用。工作站的核心约束是 TRX50 上的 Pro CPU 降配运行——内存通道从 8 条被主板物理走线限制为 4 条。服务器层面涉及通道对称填充、NUMA 交错策略、ECC 故障处理、Rank 数量对频率的影响，以及内存功耗和散热——单台 Genoa 服务器仅内存的持续功耗就可超过 200W。</p><h2 id="内容结构" tabindex="-1">内容结构 <a class="header-anchor" href="#内容结构" aria-label="Permalink to “内容结构”">​</a></h2><ul><li><a href="./consumer">消费级主板</a>：插槽形态（PCIe/M.2/SATA）、芯片组原理、Intel/AMD 主板型号对照</li><li><a href="./workstation">工作站主板</a>：Threadripper 平台演进、TRX50 vs WRX90 选型</li><li><a href="./server">服务器主板</a>：EPYC 命名规则、SP3/SP5/SP6 平台、BMC 带外管理、NUMA 拓扑</li><li><a href="./ram">主板与内存的适配</a>：三级平台的内存约束、填充规则、ECC 故障处理</li></ul>`,12)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};